// ─────────────────────────────────────────────────────────────
// REPLACE THIS: paste your free Gemini API key between the quotes
// Get one (no credit card needed) at https://aistudio.google.com/apikey
// ─────────────────────────────────────────────────────────────
const GEMINI_API_KEY = 'AQ.Ab8RN6Kc6yxtiqk2Z5BQ7f_9uF-OK41TySGwzgSs_602l_EyvA';
const MODEL = 'gemini-2.5-flash';
const MAX_RETRIES = 3;

// Form Trigger outputs submitted fields directly on .json,
// keyed by whatever "Field Name" was set on each form field.
const body = $input.first().json;
const topic          = body['Topic']                    || 'general topic';
const scheduled_time = body['Scheduled Date/Time']      || 'not specified';

// ── Prompt engineering strategy ────────────────────────────────
// Strategy: enforce the constraint in the system instruction (hard rule)
// AND in the user turn (reminder + direction if we're retrying).
// On subsequent attempts we tell the model which direction to adjust,
// which converges faster than a blind, unconstrained retry.
const SYSTEM_PROMPT =
  'You are a professional social media copywriter.\n' +
  'Write ONE social media post for the given topic.\n\n' +
  'STRICT RULES — violating them causes an automatic retry:\n' +
  '- Total word count: EXACTLY between 90 and 150 words.\n' +
  '- Count every word including hashtags before responding.\n' +
  '- Include 3–5 relevant hashtags at the end.\n' +
  '- Output ONLY the post text — no preamble, no word-count label.';

let generated_text = '';
let word_count = 0;
let attempts = 0;

while (attempts < MAX_RETRIES) {
  attempts++;

  // Adaptive feedback on retry: tell the model which direction it missed
  const feedback = attempts > 1
    ? `\n\nIMPORTANT: your previous attempt had ${word_count} words. ` +
      (word_count < 90 ? 'Add more content to reach at least 90 words.'
                       : 'Cut content to stay under 150 words.')
    : '';

  const payload = {
    system_instruction: { parts: [{ text: SYSTEM_PROMPT }] },
    contents: [
      { role: 'user', parts: [{ text: `Topic: ${topic}.${feedback}` }] }
    ],
    generationConfig: { temperature: 0.7, maxOutputTokens: 500, thinkingConfig: { thinkingBudget: 0 } }
  };

  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://generativelanguage.googleapis.com/v1beta/models/${MODEL}:generateContent?key=${GEMINI_API_KEY}`,
    headers: { 'Content-Type': 'application/json' },
    body: payload,
    json: true
  });

  generated_text = resp.candidates[0].content.parts[0].text.trim();
  word_count = generated_text.split(/\s+/).filter(w => w.length > 0).length;

  if (word_count >= 90 && word_count <= 150) break;
}

// If we exhausted all retries and still can't hit the range, fail loudly
if (word_count < 90 || word_count > 150) {
  throw new Error(
    `Failed to generate a post within 90–150 words after ${MAX_RETRIES} attempts. ` +
    `Last word count: ${word_count}. Check your API key and try re-running.`
  );
}

return [{
  json: { topic, scheduled_time, generated_text, word_count, llm_attempts: attempts }
}];

// ─────────────────────────────────────────────────────────────
// REPLACE THESE THREE VALUES with your Cloudinary details.
//
// Where to find them:
//   CLOUD_NAME    → cloudinary.com dashboard, top-left
//   BACKGROUND_ID → public_id shown after uploading your
//                   background / brand template image
//   LOGO_ID       → public_id shown after uploading your logo
//
// Transformation applied (pixel-perfect, same every run):
//   Logo  : top-right corner, 20px from edges, scaled to 120px wide
//   Title : lower-middle,     60px from bottom, white Arial bold,
//           auto-fit to 500px wide
// ─────────────────────────────────────────────────────────────
const CLOUD_NAME    = 'dfpsztll7';
const BACKGROUND_ID = 'brand_background';
const LOGO_ID       = 'brand_logo';

// const item  = $input.first().json;
// const title = (item.topic || '').slice(0, 50); // cap title length
const item  = $input.first().json;
const title = (item.topic || '').slice(0, 100); // shorter cap so it reliably fits one line
// Cloudinary text overlays encode spaces as underscores in the path segment
// const encodedTitle = encodeURIComponent(title).replace(/%20/g, '_');
// Just percent-encode — do NOT convert %20 to underscore
const encodedTitle = encodeURIComponent(title);
// Build the Cloudinary URL with two chained transformations:
// l_ = layer (overlay), g_ = gravity, x/y = offset, w_ = width,
// c_fit = fit text into the specified width without overflow
const FADE_STRENGTH = 60; // 0 = no fade, 100 = fully washed out

const layers = [
  `e_colorize:${FADE_STRENGTH},co_black`,   // dims the background — try co_white for a lighter fade instead
  `l_${LOGO_ID},g_north_east,x_20,y_20,w_120`,
  `l_text:Arial_36_bold:${encodedTitle},g_south,y_60,co_rgb:FFFFFF,w_500,h_180,c_fit`
];

const imageUrl = [
  `https://res.cloudinary.com/${CLOUD_NAME}/image/upload`,
  ...layers,
  BACKGROUND_ID
].join('/');

return [{ json: { ...item, imageUrl } }];
